const babelTypes = require('@babel/types');

/**
 * Detects if node is an enum declaration
 * @param {babel.Node} node
 */
const isEnumDeclaration = ({ declaration }) =>
  babelTypes.isEnumDeclaration(declaration) ||
  babelTypes.isTSEnumDeclaration(declaration);

/**
 * Detects if node is a type import
 * @param {babel.Node} node
 */
const isImportType = ({ importKind }) =>
  importKind === 'type' || importKind === 'typeof';

/**
 * Detects if node is a type export
 * @param {babel.Node} node
 */
const isExportType = ({ exportKind }) => exportKind === 'type';

module.exports = {
  isEnumDeclaration,
  isImportType,
  isExportType,
};
